#!/usr/bin/env python3
"""De-risk the Rust mamba2_ssd_step against HF Mamba2Mixer on a TINY random model.

Validates the exact single-token decode algorithm + the 5 risk points (in_proj split
order, gate-first RMSNorm, grouped B/C index, -exp(A_log) discretization, conv over
conv_dim). If the numpy re-implementation of the Rust step matches HF to ~1e-4, the
Rust is correct.
"""
import os
os.environ["KMP_DUPLICATE_LIB_OK"] = "TRUE"
import torch
import numpy as np
from transformers.models.mamba2.modeling_mamba2 import Mamba2Mixer, Mamba2Config

torch.manual_seed(0)
np.random.seed(0)

# Tiny config, SAME STRUCTURE as codestral (grouped multi-head SSD, rms_norm gated).
H = 64          # hidden
EXPAND = 2
D_INNER = H * EXPAND          # 128
NUM_HEADS = 4
HEAD_DIM = D_INNER // NUM_HEADS  # 32
D_STATE = 16
N_GROUPS = 2
D_CONV = 4
cfg = Mamba2Config(
    hidden_size=H, expand=EXPAND, num_heads=NUM_HEADS, head_dim=HEAD_DIM,
    state_size=D_STATE, n_groups=N_GROUPS, conv_kernel=D_CONV, chunk_size=8,
    num_hidden_layers=1, vocab_size=100, use_conv_bias=True, rms_norm=True,
    time_step_limit=(0.0, float("inf")), layer_norm_epsilon=1e-5,
)
mixer = Mamba2Mixer(cfg, layer_idx=0).eval()
for p in mixer.parameters():
    torch.nn.init.normal_(p, std=0.1)
# A_log/dt_bias sane ranges (as in real checkpoints)
with torch.no_grad():
    mixer.A_log.copy_(torch.log(torch.rand(NUM_HEADS) * 0.9 + 0.1))  # A in (0.1,1)
    mixer.dt_bias.copy_(torch.randn(NUM_HEADS) * 0.1)
    mixer.D.copy_(torch.randn(NUM_HEADS))

conv_dim = D_INNER + 2 * N_GROUPS * D_STATE
in_proj_rows = 2 * D_INNER + 2 * N_GROUPS * D_STATE + NUM_HEADS
print(f"tiny: d_inner={D_INNER} num_heads={NUM_HEADS} head_dim={HEAD_DIM} d_state={D_STATE} "
      f"n_groups={N_GROUPS} conv_dim={conv_dim} in_proj_rows={in_proj_rows}")

# ── HF single-token forward (seq_len=1, no cache = one step from zero state) ──
hidden = torch.randn(1, 1, H)
with torch.no_grad():
    out = mixer(hidden)
    hf_out = (out[0] if isinstance(out, tuple) else out).squeeze().numpy()

# ── extract weights → numpy ──
W_in = mixer.in_proj.weight.detach().numpy()      # [in_proj_rows, H]
W_conv = mixer.conv1d.weight.detach().numpy()     # [conv_dim, 1, d_conv]
b_conv = mixer.conv1d.bias.detach().numpy()       # [conv_dim]
A_log = mixer.A_log.detach().numpy()              # [num_heads]
D = mixer.D.detach().numpy()                       # [num_heads]
dt_bias = mixer.dt_bias.detach().numpy()          # [num_heads]
norm_w = mixer.norm.weight.detach().numpy()       # [d_inner]
W_out = mixer.out_proj.weight.detach().numpy()    # [H, d_inner]
hin = hidden.squeeze().numpy()                     # [H]

def softplus(x): return np.log1p(np.exp(-np.abs(x))) + np.maximum(x, 0)
def silu(x): return x / (1 + np.exp(-x))

# ── numpy port of the RUST forward_one mamba2 branch + mamba2_ssd_step ──
proj = W_in @ hin                                  # [in_proj_rows]
z   = proj[0:D_INNER]
xbc = proj[D_INNER:D_INNER + conv_dim]
dt_in = proj[D_INNER + conv_dim:D_INNER + conv_dim + NUM_HEADS]
# causal conv1d decode on a fresh (zero) buffer: out = silu(sum_k w[:,k]*window[k] + b),
# window = [0,0,0, xbc] (d_conv=4), so only the last tap (current token) is nonzero.
conv_out = np.zeros(conv_dim)
for ch in range(conv_dim):
    acc = b_conv[ch] + W_conv[ch, 0, D_CONV - 1] * xbc[ch]   # only current token (history=0)
    conv_out[ch] = silu(acc)
x = conv_out[0:D_INNER]
B = conv_out[D_INNER:D_INNER + N_GROUPS * D_STATE]
C = conv_out[D_INNER + N_GROUPS * D_STATE:D_INNER + 2 * N_GROUPS * D_STATE]
h = np.zeros((NUM_HEADS, HEAD_DIM, D_STATE))
y = np.zeros(D_INNER)
hpg = NUM_HEADS // N_GROUPS
for hh in range(NUM_HEADS):
    g = hh // hpg
    dt = softplus(dt_in[hh] + dt_bias[hh])
    dA = np.exp(dt * -np.exp(A_log[hh]))
    for p in range(HEAD_DIM):
        xp = x[hh * HEAD_DIM + p]
        yp = D[hh] * xp
        for n in range(D_STATE):
            h[hh, p, n] = dA * h[hh, p, n] + dt * xp * B[g * D_STATE + n]
            yp += C[g * D_STATE + n] * h[hh, p, n]
        y[hh * HEAD_DIM + p] = yp
# gated RMSNorm (gate-first)
yg = y * silu(z)
inv = 1.0 / np.sqrt(np.mean(yg * yg) + 1e-5)
yn = yg * inv * norm_w
mine = W_out @ yn                                  # [H]

# ── compare ──
err = np.max(np.abs(mine - hf_out))
rel = err / (np.max(np.abs(hf_out)) + 1e-9)
print(f"HF out[:4]  = {np.round(hf_out[:4], 5)}")
print(f"mine out[:4]= {np.round(mine[:4], 5)}")
print(f"max_abs_err = {err:.3e}   max_rel_err = {rel:.3e}")
print("VERDICT:", "MATCH ✅ (Rust algorithm correct)" if err < 1e-3 else "MISMATCH ❌ — debug the step")
